import{_ as e}from"./chunks/script-editor.ngC1KYbm.js";import{_ as a,o,c as r,ag as i}from"./chunks/framework._658-eYr.js";const s="/CRAFT/assets/fact-check.CTWNPFtg.png",f=JSON.parse('{"title":"Scripts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scripts.md","filePath":"guide/scripts.md"}'),n={name:"guide/scripts.md"};function l(d,t,c,h,p,u){return o(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="scripts" tabindex="-1">Scripts <a class="header-anchor" href="#scripts" aria-label="Permalink to &quot;Scripts&quot;">​</a></h1><p>The Script Editor is where ideas become content. AI writes, revises, and polishes scripts in your character&#39;s voice, with fact-checking and humanization tools.</p><h2 id="script-editor" tabindex="-1">Script Editor <a class="header-anchor" href="#script-editor" aria-label="Permalink to &quot;Script Editor&quot;">​</a></h2><p>Click any script to open the editor. The toolbar provides:</p><p><img src="'+e+'" alt="Script Editor"></p><h3 id="ai-writing" tabindex="-1">AI Writing <a class="header-anchor" href="#ai-writing" aria-label="Permalink to &quot;AI Writing&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>What It Does</th></tr></thead><tbody><tr><td><strong>Write with Voice</strong></td><td>Generates a full script from the title and any existing content</td></tr><tr><td><strong>Revise</strong></td><td>Opens a prompt input — type what to change, then submit</td></tr><tr><td><strong>Polish</strong></td><td>Fixes awkward phrasing, ensures consistent voice, improves the ending</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Revise with Instructions</p><p>Click <strong>Revise</strong> to open an inline text field. Type specific instructions like &quot;make the intro punchier&quot; or &quot;add more technical detail&quot; then press Enter.</p></div><h3 id="youtube-shorts" tabindex="-1">YouTube Shorts <a class="header-anchor" href="#youtube-shorts" aria-label="Permalink to &quot;YouTube Shorts&quot;">​</a></h3><p>Scripts marked as <strong>Short</strong> get special AI treatment:</p><ul><li>Loop structure — the last sentence trails off incomplete, completed by the first sentence on replay</li><li>~150 word target</li><li>No hashtags in content (extracted to tags automatically)</li></ul><h3 id="model-selection" tabindex="-1">Model Selection <a class="header-anchor" href="#model-selection" aria-label="Permalink to &quot;Model Selection&quot;">​</a></h3><p>The model dropdown lets you choose between Claude and Gemini models. Each has different strengths — Claude (especially Opus) may use MCP research tools, while Gemini streams faster.</p><h2 id="status-workflow" tabindex="-1">Status Workflow <a class="header-anchor" href="#status-workflow" aria-label="Permalink to &quot;Status Workflow&quot;">​</a></h2><p>Scripts progress through three statuses:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Audio</th></tr></thead><tbody><tr><td><strong>Draft</strong></td><td>Work in progress</td><td>Blocked</td></tr><tr><td><strong>Review</strong></td><td>Ready for review</td><td>Allowed</td></tr><tr><td><strong>Final</strong></td><td>Production ready</td><td>Allowed</td></tr></tbody></table><p>Change status via the dropdown in the editor toolbar.</p><h2 id="fact-check" tabindex="-1">Fact Check <a class="header-anchor" href="#fact-check" aria-label="Permalink to &quot;Fact Check&quot;">​</a></h2><p>Click <strong>Fact Check</strong> to scan the script for factual claims:</p><p><img src="'+s+'" alt="Fact Check Panel"></p><ul><li><strong>Verified</strong> (green) — confirmed accurate</li><li><strong>Unverified</strong> (amber) — plausible but not confirmed</li><li><strong>Disputed</strong> (red) — contradicts known facts</li><li><strong>Opinion</strong> (blue) — subjective, not a factual claim</li></ul><p>Click any claim to <strong>jump to that text</strong> in the editor.</p><h2 id="humanize" tabindex="-1">Humanize <a class="header-anchor" href="#humanize" aria-label="Permalink to &quot;Humanize&quot;">​</a></h2><p>Click <strong>Humanize</strong> to detect and rewrite AI-sounding passages:</p><ul><li><strong>Fixed</strong> (green) — auto-rewritten with strikethrough original and cyan replacement</li><li><strong>Flagged</strong> (amber) — needs manual attention</li></ul><p>Actions:</p><ul><li><strong>Apply All Fixes</strong> — replaces entire script with humanized version</li><li><strong>Apply this fix</strong> — replaces individual passage</li><li>Click to jump to the passage in the editor</li></ul><h2 id="word-count" tabindex="-1">Word Count <a class="header-anchor" href="#word-count" aria-label="Permalink to &quot;Word Count&quot;">​</a></h2><p>The word counter shows spoken words only — stage directions like <code>*(walks to camera)*</code>, <code>*[leans in]*</code>, and <code>[CUT TO]</code> are excluded. The progress bar fills based on the target (150 for Shorts, 1500 for Long).</p><h2 id="auto-save" tabindex="-1">Auto-Save <a class="header-anchor" href="#auto-save" aria-label="Permalink to &quot;Auto-Save&quot;">​</a></h2><p>Scripts auto-save every 30 seconds when modified. The Save button shows <code>Save*</code> when there are unsaved changes.</p>',31)])])}const b=a(n,[["render",l]]);export{f as __pageData,b as default};
